code.glsl:
uniform float uFeedRate;
uniform float uKillRate;
uniform float uDiffuseA;
uniform float uDiffuseB;
uniform float uTime;
out vec4 fragColor;

void main() {
    vec2 uv = vUV.st;
    vec2 texel = vec2(1.0) / uTDOutputInfo.res.zw;

    vec4 c = texture(sTD2DInputs[0], uv);
    float a = c.r;
    float b = c.g;

    float lapA = 0.0;
    float lapB = 0.0;

    lapA += texture(sTD2DInputs[0], uv + vec2( texel.x, 0.0)).r * 0.2;
    lapA += texture(sTD2DInputs[0], uv + vec2(-texel.x, 0.0)).r * 0.2;
    lapA += texture(sTD2DInputs[0], uv + vec2(0.0,  texel.y)).r * 0.2;
    lapA += texture(sTD2DInputs[0], uv + vec2(0.0, -texel.y)).r * 0.2;
    lapA += texture(sTD2DInputs[0], uv + vec2( texel.x,  texel.y)).r * 0.05;
    lapA += texture(sTD2DInputs[0], uv + vec2(-texel.x,  texel.y)).r * 0.05;
    lapA += texture(sTD2DInputs[0], uv + vec2( texel.x, -texel.y)).r * 0.05;
    lapA += texture(sTD2DInputs[0], uv + vec2(-texel.x, -texel.y)).r * 0.05;
    lapA -= a;

    lapB += texture(sTD2DInputs[0], uv + vec2( texel.x, 0.0)).g * 0.2;
    lapB += texture(sTD2DInputs[0], uv + vec2(-texel.x, 0.0)).g * 0.2;
    lapB += texture(sTD2DInputs[0], uv + vec2(0.0,  texel.y)).g * 0.2;
    lapB += texture(sTD2DInputs[0], uv + vec2(0.0, -texel.y)).g * 0.2;
    lapB += texture(sTD2DInputs[0], uv + vec2( texel.x,  texel.y)).g * 0.05;
    lapB += texture(sTD2DInputs[0], uv + vec2(-texel.x,  texel.y)).g * 0.05;
    lapB += texture(sTD2DInputs[0], uv + vec2( texel.x, -texel.y)).g * 0.05;
    lapB += texture(sTD2DInputs[0], uv + vec2(-texel.x, -texel.y)).g * 0.05;
    lapB -= b;

    float abb = a * b * b;
    float newA = a + uDiffuseA * lapA - abb + uFeedRate * (1.0 - a);
    float newB = b + uDiffuseB * lapB + abb - (uKillRate + uFeedRate) * b;

    fragColor = TDOutputSwizzle(vec4(clamp(newA, 0.0, 1.0), clamp(newB, 0.0, 1.0), 0.0, 1.0));
}
